class Solution:
    def sumAndMultiply(self, s, queries):
        MOD = 10**9 + 7
        ans = []
        for l, r in queries:
            digits = [c for c in s[l:r+1] if c != '0']
            if digits:
                x = int(''.join(digits))
                total = sum(int(c) for c in digits)
            else:
                x = 0
                total = 0
            ans.append((x * total) % MOD)
        return ans

