var sumAndMultiply = function(s, queries) {
    const MOD = 1000000007n;
    const m = s.length;
    const P = new Array(m + 1).fill(0n);
    const cnt = new Array(m + 1).fill(0);
    const dsum = new Array(m + 1).fill(0);
    for (let i = 1; i <= m; i++) {
        const d = s.charCodeAt(i - 1) - 48;
        if (d === 0) {
            P[i] = P[i - 1];
            cnt[i] = cnt[i - 1];
        } else {
            P[i] = (P[i - 1] * 10n + BigInt(d)) % MOD;
            cnt[i] = cnt[i - 1] + 1;
        }
        dsum[i] = dsum[i - 1] + d;
    }
    const pow10 = new Array(m + 2).fill(1n);
    for (let i = 1; i <= m + 1; i++) pow10[i] = (pow10[i - 1] * 10n) % MOD;
    const ans = [];
    for (const [l, r] of queries) {
        const L = l, R = r + 1;
        const k = cnt[R] - cnt[L];
        let xval = (P[R] - P[L] * pow10[k]) % MOD;
        if (xval < 0n) xval += MOD;
        const sumVal = BigInt(dsum[R] - dsum[L]);
        let a = (xval * sumVal) % MOD;
        if (a < 0n) a += MOD;
        ans.push(Number(a));
    }
    return ans;
};
